// Auto-heal generated-file conflicts on open pull requests.  Run by the
// heal-generated-files workflow after main moves (or on manual dispatch).  For each
// same-repo PR that conflicts with main ONLY in generated files - the pnpm
// lockfile and/or the autogenerated README.AUTOGEN.md companions - merge main
// into the PR branch, resolve those files, and push the result so the PR (and
// the merge queue) stops choking on them.  The lockfile is rebuilt with pnpm;
// the READMEs keep our copy and are regenerated by the docs-pr-amend workflow
// that re-runs on the healed push.  PRs that conflict in any other file are
// left untouched for a human to resolve.

import { execFileSync } from "node:child_process";

const LOCKFILE = "ts/pnpm-lock.yaml";
const REPO = process.env.GITHUB_REPOSITORY;
const ONLY_PR = process.env.INPUT_PR?.trim();

// All git/gh/pnpm calls go through execFileSync with an argument array (no
// shell), so branch names coming from the API can never be interpreted by a
// shell.
function run(cmd, args, opts = {}) {
    return execFileSync(cmd, args, {
        encoding: "utf8",
        stdio: ["ignore", "pipe", "pipe"],
        ...opts,
    });
}

function tryRun(cmd, args, opts = {}) {
    try {
        return { ok: true, out: run(cmd, args, opts) };
    } catch (err) {
        return { ok: false, out: `${err.stdout ?? ""}${err.stderr ?? ""}` };
    }
}

function candidatePRs() {
    if (ONLY_PR) {
        const p = JSON.parse(
            run("gh", [
                "pr",
                "view",
                ONLY_PR,
                "--repo",
                REPO,
                "--json",
                "number,headRefName,isCrossRepository",
            ]),
        );
        if (p.isCrossRepository) {
            console.log(
                `[heal] PR #${ONLY_PR} is from a fork - cannot push, skipping`,
            );
            return [];
        }
        return [{ number: p.number, ref: p.headRefName }];
    }
    // Open PRs targeting main, from this repo (fork branches aren't pushable),
    // that aren't already cleanly mergeable.  A trial merge decides the rest.
    const prs = JSON.parse(
        run("gh", [
            "pr",
            "list",
            "--repo",
            REPO,
            "--state",
            "open",
            "--base",
            "main",
            "--limit",
            "100",
            "--json",
            "number,mergeable,isCrossRepository,headRefName",
        ]),
    );
    return prs
        .filter((p) => !p.isCrossRepository && p.mergeable !== "MERGEABLE")
        .map((p) => ({ number: p.number, ref: p.headRefName }));
}

function unmergedFiles() {
    return run("git", ["diff", "--name-only", "--diff-filter=U"])
        .split("\n")
        .map((s) => s.trim())
        .filter(Boolean);
}

// Generated files we can resolve automatically after merging main.  A conflict
// in anything else means a human needs to look at the PR.
function isAutogenReadme(file) {
    return /^ts\/packages\/.+\/README\.AUTOGEN\.md$/.test(file);
}

function isResolvable(file) {
    return file === LOCKFILE || isAutogenReadme(file);
}

// Resolve the merged-in conflicts in place and stage the results.
function resolveConflicts(conflicts) {
    // Autogen READMEs: keep our copy.  The docs-pr-amend workflow regenerates
    // them from the merged source on the healed push (it re-runs because we push
    // with the app token), so no build or model access is needed here.
    for (const file of conflicts.filter(isAutogenReadme)) {
        run("git", ["checkout", "--ours", "--", file]);
        run("git", ["add", file]);
    }

    // Lockfile: seed from main's copy, then let pnpm rebuild it against the
    // merged package.json files.
    if (conflicts.includes(LOCKFILE)) {
        run("git", ["checkout", "--theirs", "--", LOCKFILE]);
        run(
            "pnpm",
            [
                "install",
                "--lockfile-only",
                "--no-frozen-lockfile",
                "--ignore-scripts",
            ],
            { cwd: "ts", stdio: "inherit" },
        );
        run("git", ["add", LOCKFILE]);
    }
}

function healPr({ number, ref }) {
    console.log(`\n[heal] PR #${number} (${ref})`);
    try {
        run("git", ["fetch", "origin", "main", ref]);
        run("git", ["checkout", "-B", "_heal", `origin/${ref}`]);

        // Trial-merge main.  --no-ff/--no-commit so a clean merge leaves a
        // MERGE_HEAD we simply discard, and a conflicted one leaves the unmerged
        // set to inspect.
        tryRun("git", ["merge", "--no-ff", "--no-commit", "origin/main"]);
        const conflicts = unmergedFiles();

        if (conflicts.length === 0) {
            console.log("[heal] no conflict - skipping");
            return;
        }
        if (!conflicts.every(isResolvable)) {
            const other = conflicts.filter((f) => !isResolvable(f));
            console.log(
                `[heal] conflicts beyond generated files (${other.join(", ")}) - leaving for a human`,
            );
            return;
        }

        resolveConflicts(conflicts);
        run("git", ["commit", "--no-edit"]);

        // Non-force push: if the PR head moved meanwhile the push is rejected and
        // the next run retries, so a concurrent update is never clobbered.
        const push = tryRun("git", ["push", "origin", `_heal:${ref}`]);
        if (push.ok) {
            console.log(
                `[heal] PR #${number}: resolved ${conflicts.join(", ")} and pushed`,
            );
        } else {
            console.log(
                `[heal] PR #${number}: push rejected (branch moved?) - will retry\n${push.out}`,
            );
        }
    } finally {
        // Return to a clean, detached state so the next PR starts fresh.  This
        // only touches the ephemeral CI checkout and the throwaway _heal branch.
        tryRun("git", ["merge", "--abort"]);
        tryRun("git", ["reset", "--hard"]);
        tryRun("git", ["checkout", "--detach", "origin/main"]);
        tryRun("git", ["branch", "-D", "_heal"]);
    }
}

const prs = candidatePRs();
if (prs.length === 0) {
    console.log("[heal] nothing to do - no conflicting same-repo PRs");
    process.exit(0);
}

run("git", ["config", "user.name", "typeagent-bot"]);
run("git", [
    "config",
    "user.email",
    "typeagent-bot[bot]@users.noreply.github.com",
]);

let failures = 0;
for (const pr of prs) {
    try {
        healPr(pr);
    } catch (err) {
        failures++;
        console.error(`[heal] PR #${pr.number} failed: ${err.message}`);
    }
}
process.exit(failures ? 1 : 0);
